typedef long long int llint;
#include<stdio.h>
int main()
{
    llint r1;
    double y;
    scanf("%lld",&r1);
    double r=r1;

    for (llint i=1;i>0;i++)
    {
        y=(r-i-1-i*i)/(2*i);
        llint y1=y;
        if (y1==y&&y>0)
        {
          printf("%lld %lld",i,y1);
          return(0);
        }
        if (y<1)
        {
          printf("NO");
          return(0);
        }

    }
    return(0);
}

